const secsEl = document.getElementById('secs');
const c1 = document.getElementById('c1'), e1 = document.getElementById('e1');
const orbs = [];
let total = 0;

SECS.forEach(s => {
  const sec = document.createElement('section');
  sec.className = 'sec';

  const hd = document.createElement('div');
  hd.className = 'sec-head';
  const num = document.createElement('div'); num.className = 'sec-num'; num.textContent = s.n;
  const h2 = document.createElement('h2'); h2.textContent = s.t;
  const sp = document.createElement('span'); sp.textContent = s.sub;
  hd.append(num, h2, sp);

  const grid = document.createElement('div');
  grid.className = 'grid';

  s.p.forEach(([name, cat, desc]) => {
    total++;
    const card = document.createElement('article');
    card.className = 'card';
    card.dataset.q = (name + ' ' + cat + ' ' + desc).toLowerCase();

    const tag = document.createElement('span'); tag.className = 'tag'; tag.textContent = cat;
    const h3 = document.createElement('h3'); h3.textContent = name;
    const p = document.createElement('p'); p.textContent = desc;

    const row = document.createElement('div'); row.className = 'orbs';
    const lb = document.createElement('span'); lb.className = 'lb'; lb.textContent = 'Images';
    row.appendChild(lb);
    ENG.forEach(en => {
      const a = document.createElement('a');
      a.className = 'orb'; a.target = '_blank'; a.rel = 'noopener';
      a.innerHTML = en.s;
      row.appendChild(a);
      orbs.push({ a, en, name });
    });

    card.append(tag, h3, p, row);
    grid.appendChild(card);
  });

  sec.append(hd, grid);
  secsEl.appendChild(sec);
});

function retarget() {
  orbs.forEach(o => {
    const q = o.name + ' ' + SFX;
    o.a.href = o.en.u(q);
    o.a.title = o.en.k + ' — ' + q;
    o.a.setAttribute('aria-label', o.en.k + ' image search for ' + q);
  });
}
retarget();
c1.textContent = total + ' products';

document.querySelectorAll('[data-sfx]').forEach(b => b.addEventListener('click', () => {
  document.querySelectorAll('[data-sfx]').forEach(x => x.setAttribute('aria-pressed', 'false'));
  b.setAttribute('aria-pressed', 'true');
  SFX = b.dataset.sfx;
  retarget();
}));

document.getElementById('q1').addEventListener('input', e => {
  const q = e.target.value.trim().toLowerCase();
  let n = 0;
  document.querySelectorAll('.sec').forEach(sec => {
    let v = 0;
    sec.querySelectorAll('.card').forEach(c => {
      const hit = !q || c.dataset.q.includes(q);
      c.classList.toggle('off', !hit);
      if (hit) { v++; n++; }
    });
    sec.classList.toggle('off', v === 0);
  });
  e1.hidden = n > 0;
  c1.textContent = q ? n + ' of ' + total + ' products' : total + ' products';
});

/* ========== DICTIONARY ========== */
const tlist = document.getElementById('tlist');
const azEl = document.getElementById('az');
const c2 = document.getElementById('c2'), e2 = document.getElementById('e2');
let LTR = null;

const nAws = DATA.terms.filter(t => t.s === 'A').length;
document.getElementById('dsub').textContent =
  DATA.terms.length + ' terms — the drafting dictionary plus ' + nAws +
  ' lifted from the official AWS glossary. Green bar = AWS.';

const nodes = DATA.terms.map(t => {
  const w = document.createElement('div');
  w.className = 'tm';
  w.dataset.s = t.s;
  w.dataset.l = t.l;
  w.dataset.q = (t.t + ' ' + t.d).toLowerCase();
  const dt = document.createElement('dt');
  const dd = document.createElement('dd');
  w.append(dt, dd);
  tlist.appendChild(w);
  return { w, dt, dd, t };
});

const present = new Set(DATA.terms.map(t => t.l));
const all = document.createElement('button');
all.textContent = 'All'; all.setAttribute('aria-pressed', 'true');
azEl.appendChild(all);
const btns = [all];
'ABCDEFGHIJKLMNOPQRSTUVWXYZ'.split('').forEach(L => {
  const b = document.createElement('button');
  b.textContent = L; b.setAttribute('aria-pressed', 'false');
  if (!present.has(L)) b.disabled = true;
  b.addEventListener('click', () => { LTR = LTR === L ? null : L; syncAz(); filterD(); });
  azEl.appendChild(b); btns.push(b);
});
all.addEventListener('click', () => { LTR = null; syncAz(); filterD(); });
function syncAz() {
  btns.forEach(b => b.setAttribute('aria-pressed',
    (b === all ? LTR === null : b.textContent === LTR) ? 'true' : 'false'));
}

function hl(el, text, q, tail) {
  el.textContent = '';
  const i = q ? text.toLowerCase().indexOf(q) : -1;
  if (i < 0) el.append(document.createTextNode(text));
  else el.append(
    document.createTextNode(text.slice(0, i)),
    Object.assign(document.createElement('mark'), { textContent: text.slice(i, i + q.length) }),
    document.createTextNode(text.slice(i + q.length))
  );
  if (tail) el.appendChild(tail);
}

function filterD() {
  const q = document.getElementById('q2').value.trim().toLowerCase();
  let n = 0;
  nodes.forEach(x => {
    const hit = (!q || x.w.dataset.q.includes(q)) && (!LTR || x.w.dataset.l === LTR);
    x.w.classList.toggle('off', !hit);
    if (!hit) return;
    n++;
    let tail = null;
    if (x.t.s === 'A') {
      tail = document.createElement('span');
      tail.className = 'src';
      tail.textContent = 'AWS';
    }
    hl(x.dt, x.t.t, q, tail);
    hl(x.dd, x.t.d, q, null);
  });
  e2.hidden = n > 0;
  c2.textContent = (q || LTR) ? n + ' of ' + DATA.terms.length + ' terms' : DATA.terms.length + ' terms';
}
document.getElementById('q2').addEventListener('input', filterD);
filterD();

const ab = document.getElementById('ab');
DATA.abbrevs.forEach(a => {
  const tr = document.createElement('tr');
  const t1 = document.createElement('td'); t1.textContent = a.a;
  const t2 = document.createElement('td'); t2.textContent = a.m;
  tr.append(t1, t2); ab.appendChild(tr);
});

document.querySelectorAll('[data-dv]').forEach(b => b.addEventListener('click', () => {
  document.querySelectorAll('[data-dv]').forEach(x => x.setAttribute('aria-pressed', 'false'));
  b.setAttribute('aria-pressed', 'true');
  const isT = b.dataset.dv === 't';
  document.getElementById('dterms').hidden = !isT;
  document.getElementById('dabbr').hidden = isT;
  document.getElementById('dfind').style.visibility = isT ? 'visible' : 'hidden';
  if (isT) filterD();
  else c2.textContent = DATA.abbrevs.length + ' abbreviations';
}));

/* ========== STANDARD ========== */
const toc = document.getElementById('toc'), doc = document.getElementById('doc');
const c3 = document.getElementById('c3');
const tb = [];
let lastG = null;

DATA.awi.forEach((ch, i) => {
  if (ch.g !== lastG) {
    const g = document.createElement('div');
    g.className = 'toc-g'; g.textContent = ch.g;
    toc.appendChild(g); lastG = ch.g;
  }
  const b = document.createElement('button');
  const badge = document.createElement('i');
  badge.textContent = ch.n || '·';
  b.appendChild(badge);
  b.appendChild(document.createTextNode(ch.t));
  b.dataset.q = (ch.t + ' ' + (ch.inc || []).join(' ') + ' ' +
                 ch.h.replace(/<[^>]+>/g, ' ')).toLowerCase();
  b.setAttribute('aria-current', i === 0 ? 'true' : 'false');
  b.addEventListener('click', () => show(i));
  toc.appendChild(b); tb.push(b);
});

function show(i) {
  const ch = DATA.awi[i];
  tb.forEach((b, j) => b.setAttribute('aria-current', j === i ? 'true' : 'false'));

  doc.textContent = '';
  const hd = document.createElement('div');
  hd.className = 'doc-hd';
  const n = document.createElement('div');
  n.className = 'n'; n.textContent = ch.n || '§';
  const h2 = document.createElement('h2'); h2.textContent = ch.t;
  hd.append(n, h2);
  doc.appendChild(hd);

  if (ch.inc) {
    const se = document.createElement('div');
    se.className = 'se';
    [['in', 'In your scope', ch.inc], ['ex', 'Not your scope', ch.exc]].forEach(([cls, label, items]) => {
      const box = document.createElement('div');
      box.className = cls;
      const h4 = document.createElement('h4'); h4.textContent = label;
      const ul = document.createElement('ul');
      (items || []).forEach(t => {
        const li = document.createElement('li'); li.textContent = t; ul.appendChild(li);
      });
      box.append(h4, ul); se.appendChild(box);
    });
    doc.appendChild(se);
  }

  const body = document.createElement('div');
  body.innerHTML = ch.h;
  doc.appendChild(body);
  doc.scrollIntoView({ block: 'nearest' });
}
show(0);
c3.textContent = DATA.awi.length + ' entries';

document.getElementById('q3').addEventListener('input', e => {
  const q = e.target.value.trim().toLowerCase();
  let n = 0;
  tb.forEach(b => {
    const hit = !q || b.dataset.q.includes(q);
    b.classList.toggle('off', !hit);
    if (hit) n++;
  });
  c3.textContent = q ? n + ' of ' + DATA.awi.length + ' entries' : DATA.awi.length + ' entries';
});

/* ========== TABS ========== */
document.querySelectorAll('.tab').forEach(t => t.addEventListener('click', () => {
  document.querySelectorAll('.tab').forEach(x => x.setAttribute('aria-selected', 'false'));
  t.setAttribute('aria-selected', 'true');
  document.querySelectorAll('.view').forEach(v => v.classList.remove('on'));
  document.getElementById('v-' + t.dataset.view).classList.add('on');
  document.body.dataset.view = t.dataset.view;
  window.scrollTo({ top: 0 });
}));